#!/usr/bin/env node
// Breaking Change Detector for Azure SDK for JS
// Compares api.md files (generated by API Extractor) between baseline and current state
// to detect breaking changes introduced by TypeSpec regeneration.

const { execSync } = require("child_process");
const fs = require("fs");
const path = require("path");

// === CLI Arguments ===
function getArg(name, defaultValue = "") {
  const index = process.argv.indexOf(name);
  if (index < 0 || index + 1 >= process.argv.length) return defaultValue;
  return process.argv[index + 1];
}

function hasFlag(name) {
  return process.argv.includes(name);
}

const sdkRoot = process.cwd();
const baselineSha = getArg("--baseline", "HEAD");
const packagesFile = getArg("--packages", "");
const failOnBreaking = !hasFlag("--no-fail");
const verbose = hasFlag("--verbose");

// === API Surface Parsing ===

/**
 * Extract TypeScript code from api.md markdown fences.
 * Returns the concatenated content of all ```ts ... ``` blocks.
 */
function extractCodeFromApiMd(content) {
  const blocks = [];
  const fenceRegex = /```ts\s*\n([\s\S]*?)```/g;
  let match;
  while ((match = fenceRegex.exec(content)) !== null) {
    blocks.push(match[1]);
  }
  return blocks.join("\n");
}

/**
 * Parse TypeScript declarations from api.md code content into a structured API map.
 *
 * Returns: Map<string, ApiSymbol>
 *   where ApiSymbol = { kind, name, signature, members?: ApiMember[] }
 *   and ApiMember = { name, signature, optional, readonly }
 */
function parseApiSurface(code) {
  const symbols = new Map();
  const lines = code.split(/\r?\n/);
  let i = 0;

  while (i < lines.length) {
    const line = lines[i];

    // Skip comments, blank lines, import statements
    if (!line.trim() || line.trim().startsWith("//") || line.trim().startsWith("import ")) {
      i++;
      continue;
    }

    // Detect export declarations
    const exportMatch = line.match(
      /^export\s+(class|interface|enum|function|type|const|namespace)\s+([^\s<({:=]+)/
    );

    if (exportMatch) {
      const kind = exportMatch[1];
      const name = exportMatch[2];

      if (kind === "function" || kind === "const") {
        // Single-line or multi-line function/const declaration
        const fullSig = collectFullDeclaration(lines, i);
        symbols.set(name, { kind, name, signature: normalizeSignature(fullSig) });
        i += countDeclarationLines(lines, i);
        continue;
      }

      if (kind === "type") {
        const fullSig = collectFullDeclaration(lines, i);
        symbols.set(name, { kind, name, signature: normalizeSignature(fullSig) });
        i += countDeclarationLines(lines, i);
        continue;
      }

      if (kind === "class" || kind === "interface" || kind === "enum" || kind === "namespace") {
        const blockResult = collectBlock(lines, i);
        const members = parseMembers(blockResult.body, kind);
        const extendsClause = extractExtends(line);
        symbols.set(name, {
          kind,
          name,
          signature: normalizeSignature(blockResult.header),
          extends: extendsClause,
          members,
        });
        i = blockResult.endIndex + 1;
        continue;
      }
    }

    // Handle re-exports: export { Foo }
    const reExportMatch = line.match(/^export\s*\{([^}]+)\}/);
    if (reExportMatch) {
      const names = reExportMatch[1].split(",").map((n) => n.trim().split(/\s+as\s+/).pop().trim());
      for (const n of names) {
        if (n && !symbols.has(n)) {
          symbols.set(n, { kind: "re-export", name: n, signature: line.trim() });
        }
      }
      i++;
      continue;
    }

    i++;
  }

  return symbols;
}

function normalizeSignature(sig) {
  return sig.replace(/\s+/g, " ").trim();
}

function extractExtends(headerLine) {
  const match = headerLine.match(/extends\s+(.+?)\s*\{/);
  return match ? match[1].trim() : "";
}

/**
 * Collect a full single-line or multi-line declaration (no braces block).
 * Ends at semicolon or next export.
 */
function collectFullDeclaration(lines, startIndex) {
  let result = "";
  let parenDepth = 0;
  let angleDepth = 0;

  for (let i = startIndex; i < lines.length; i++) {
    const line = lines[i];
    result += (i === startIndex ? "" : " ") + line.trim();

    for (const ch of line) {
      if (ch === "(") parenDepth++;
      if (ch === ")") parenDepth--;
      if (ch === "<") angleDepth++;
      if (ch === ">") angleDepth--;
    }

    if (parenDepth <= 0 && angleDepth <= 0 && (line.includes(";") || line.match(/\)\s*$/))) {
      break;
    }
  }
  return result;
}

function countDeclarationLines(lines, startIndex) {
  let parenDepth = 0;
  let angleDepth = 0;
  let count = 0;

  for (let i = startIndex; i < lines.length; i++) {
    const line = lines[i];
    count++;

    for (const ch of line) {
      if (ch === "(") parenDepth++;
      if (ch === ")") parenDepth--;
      if (ch === "<") angleDepth++;
      if (ch === ">") angleDepth--;
    }

    if (parenDepth <= 0 && angleDepth <= 0 && (line.includes(";") || line.match(/\)\s*$/))) {
      break;
    }
  }
  return count;
}

/**
 * Collect a block (class/interface/enum body) starting from the declaration line.
 * Returns { header, body, endIndex }
 */
function collectBlock(lines, startIndex) {
  let braceDepth = 0;
  let started = false;
  let header = "";
  const bodyLines = [];
  let endIndex = startIndex;

  for (let i = startIndex; i < lines.length; i++) {
    const line = lines[i];

    for (const ch of line) {
      if (ch === "{") {
        if (!started) started = true;
        braceDepth++;
      }
      if (ch === "}") braceDepth--;
    }

    if (!started) {
      header += " " + line.trim();
    } else if (braceDepth === 0 && started) {
      endIndex = i;
      break;
    } else {
      // Inside block body (depth >= 1 after opening brace)
      if (i !== startIndex || !line.includes("{")) {
        bodyLines.push(line);
      } else {
        // First line may contain both header and opening brace
        header += " " + line.trim();
      }
    }

    if (i === startIndex) {
      header = line.trim();
      if (line.includes("{") && braceDepth > 0) {
        // Body starts on next line
      }
    }
    endIndex = i;
  }

  return { header: header.trim(), body: bodyLines.join("\n"), endIndex };
}

/**
 * Parse members from a class/interface/enum body.
 */
function parseMembers(body, parentKind) {
  const members = [];
  const lines = body.split(/\r?\n/);

  for (let i = 0; i < lines.length; i++) {
    let line = lines[i].trim();
    if (!line || line.startsWith("//") || line === "{" || line === "}") continue;

    // Remove trailing comma/semicolon for enum members
    const cleanLine = line.replace(/[,;]\s*$/, "");

    if (parentKind === "enum") {
      const enumMatch = cleanLine.match(/^(\w+)\s*=\s*(.+)/);
      if (enumMatch) {
        members.push({
          name: enumMatch[1],
          signature: cleanLine,
          optional: false,
          readonly: false,
        });
      } else if (cleanLine.match(/^\w+$/)) {
        members.push({ name: cleanLine, signature: cleanLine, optional: false, readonly: false });
      }
      continue;
    }

    // Class/interface members
    const isReadonly = line.startsWith("readonly ");
    if (isReadonly) line = line.replace(/^readonly\s+/, "");

    const isOptional = /\?\s*:/.test(line) || /\?\s*\(/.test(line);

    // Method signature: name(...): ...
    const methodMatch = line.match(/^(\w+)\s*[(<(]/);
    // Property: name: type or name?: type
    const propMatch = line.match(/^(\w+)\??\s*:/);

    let memberName = "";
    if (methodMatch) {
      memberName = methodMatch[1];
    } else if (propMatch) {
      memberName = propMatch[1];
    } else {
      // Constructor or complex signature
      if (line.startsWith("constructor")) {
        memberName = "constructor";
      } else if (line.startsWith("[")) {
        memberName = "[index-signature]";
      } else {
        memberName = line.slice(0, 30);
      }
    }

    // Collect multi-line members
    let fullSig = line;
    let depth = 0;
    for (const ch of line) {
      if (ch === "(" || ch === "{" || ch === "<") depth++;
      if (ch === ")" || ch === "}" || ch === ">") depth--;
    }
    while (depth > 0 && i + 1 < lines.length) {
      i++;
      const nextLine = lines[i].trim();
      fullSig += " " + nextLine;
      for (const ch of nextLine) {
        if (ch === "(" || ch === "{" || ch === "<") depth++;
        if (ch === ")" || ch === "}" || ch === ">") depth--;
      }
    }

    members.push({
      name: memberName,
      signature: normalizeSignature(fullSig),
      optional: isOptional,
      readonly: isReadonly,
    });
  }

  return members;
}

// === Git Baseline ===

function getBaselineFile(filePath, sha) {
  const relative = path.relative(sdkRoot, filePath).replace(/\\/g, "/");
  try {
    return execSync(`git show ${sha}:${relative}`, { encoding: "utf8", cwd: sdkRoot });
  } catch {
    return null; // File doesn't exist in baseline
  }
}

function listBaselineApiMdFiles(pkgDir, sha) {
  const relative = path.relative(sdkRoot, pkgDir).replace(/\\/g, "/");
  try {
    const output = execSync(`git ls-tree --name-only ${sha} ${relative}/review/`, {
      encoding: "utf8",
      cwd: sdkRoot,
    });
    return output
      .trim()
      .split("\n")
      .filter((f) => f.endsWith(".api.md"))
      .map((f) => path.join(sdkRoot, f.replace(/\//g, path.sep)));
  } catch {
    return [];
  }
}

// === Comparison Engine ===

/**
 * Compare two API surfaces and produce a change report.
 */
function compareApiSurfaces(oldApi, newApi) {
  const breaking = [];
  const additive = [];
  const potentiallyBreaking = [];

  // Check for removed symbols
  for (const [name, oldSymbol] of oldApi) {
    if (!newApi.has(name)) {
      breaking.push({
        type: "removed-export",
        symbol: name,
        kind: oldSymbol.kind,
        detail: `Removed ${oldSymbol.kind} "${name}"`,
      });
    }
  }

  // Check for added symbols
  for (const [name, newSymbol] of newApi) {
    if (!oldApi.has(name)) {
      additive.push({
        type: "added-export",
        symbol: name,
        kind: newSymbol.kind,
        detail: `Added ${newSymbol.kind} "${name}"`,
      });
    }
  }

  // Check for modified symbols
  for (const [name, oldSymbol] of oldApi) {
    const newSymbol = newApi.get(name);
    if (!newSymbol) continue;

    // Kind change is breaking
    if (oldSymbol.kind !== newSymbol.kind) {
      breaking.push({
        type: "kind-changed",
        symbol: name,
        detail: `"${name}" changed from ${oldSymbol.kind} to ${newSymbol.kind}`,
      });
      continue;
    }

    // For function/type/const: compare signatures
    if (["function", "const", "type", "re-export"].includes(oldSymbol.kind)) {
      if (oldSymbol.signature !== newSymbol.signature) {
        potentiallyBreaking.push({
          type: "signature-changed",
          symbol: name,
          kind: oldSymbol.kind,
          detail: `"${name}" signature changed`,
          old: oldSymbol.signature,
          new: newSymbol.signature,
        });
      }
      continue;
    }

    // For class/interface/enum: compare extends and members
    if (oldSymbol.extends !== newSymbol.extends) {
      potentiallyBreaking.push({
        type: "extends-changed",
        symbol: name,
        detail: `"${name}" extends changed: "${oldSymbol.extends}" → "${newSymbol.extends}"`,
      });
    }

    compareMembers(name, oldSymbol, newSymbol, breaking, additive, potentiallyBreaking);
  }

  return { breaking, additive, potentiallyBreaking };
}

function compareMembers(symbolName, oldSymbol, newSymbol, breaking, additive, potentiallyBreaking) {
  const oldMembers = new Map((oldSymbol.members || []).map((m) => [m.name, m]));
  const newMembers = new Map((newSymbol.members || []).map((m) => [m.name, m]));

  // Removed members
  for (const [mName, oldMember] of oldMembers) {
    if (!newMembers.has(mName)) {
      breaking.push({
        type: "removed-member",
        symbol: `${symbolName}.${mName}`,
        detail: `Removed member "${mName}" from ${oldSymbol.kind} "${symbolName}"`,
      });
    }
  }

  // Added members
  for (const [mName, newMember] of newMembers) {
    if (!oldMembers.has(mName)) {
      if (newMember.optional || oldSymbol.kind === "enum") {
        additive.push({
          type: "added-member",
          symbol: `${symbolName}.${mName}`,
          detail: `Added ${newMember.optional ? "optional " : ""}member "${mName}" to ${oldSymbol.kind} "${symbolName}"`,
        });
      } else {
        // Required member addition is breaking for interfaces (consumers may implement them)
        if (oldSymbol.kind === "interface") {
          breaking.push({
            type: "added-required-member",
            symbol: `${symbolName}.${mName}`,
            detail: `Added required member "${mName}" to interface "${symbolName}" (breaking for implementors)`,
          });
        } else {
          additive.push({
            type: "added-member",
            symbol: `${symbolName}.${mName}`,
            detail: `Added member "${mName}" to ${oldSymbol.kind} "${symbolName}"`,
          });
        }
      }
    }
  }

  // Modified members
  for (const [mName, oldMember] of oldMembers) {
    const newMember = newMembers.get(mName);
    if (!newMember) continue;

    if (oldMember.signature !== newMember.signature) {
      potentiallyBreaking.push({
        type: "member-signature-changed",
        symbol: `${symbolName}.${mName}`,
        detail: `Member "${mName}" in "${symbolName}" signature changed`,
        old: oldMember.signature,
        new: newMember.signature,
      });
    }

    // Optional → required is breaking
    if (oldMember.optional && !newMember.optional) {
      breaking.push({
        type: "optional-to-required",
        symbol: `${symbolName}.${mName}`,
        detail: `"${symbolName}.${mName}" changed from optional to required`,
      });
    }
  }
}

// === File Discovery ===

function findCurrentApiMdFiles(pkgDir) {
  const reviewDir = path.join(pkgDir, "review");
  if (!fs.existsSync(reviewDir)) return [];
  return fs
    .readdirSync(reviewDir)
    .filter((f) => f.endsWith(".api.md"))
    .map((f) => path.join(reviewDir, f));
}

// === Package Processing ===

function processPackage(pkgDir) {
  const currentFiles = findCurrentApiMdFiles(pkgDir);
  const baselineFiles = listBaselineApiMdFiles(pkgDir, baselineSha);

  // Union of all api.md file paths (handle deleted files)
  const allFiles = new Set([
    ...currentFiles.map((f) => path.basename(f)),
    ...baselineFiles.map((f) => path.basename(f)),
  ]);

  const report = { breaking: [], additive: [], potentiallyBreaking: [] };

  for (const fileName of allFiles) {
    const currentPath = path.join(pkgDir, "review", fileName);
    const currentContent = fs.existsSync(currentPath) ? fs.readFileSync(currentPath, "utf8") : null;
    const baselineContent = getBaselineFile(currentPath, baselineSha);

    if (!baselineContent && currentContent) {
      // New api.md file — all additive
      const api = parseApiSurface(extractCodeFromApiMd(currentContent));
      for (const [name, sym] of api) {
        report.additive.push({
          type: "added-export",
          symbol: name,
          kind: sym.kind,
          detail: `Added ${sym.kind} "${name}" (new API file: ${fileName})`,
        });
      }
      continue;
    }

    if (baselineContent && !currentContent) {
      // Deleted api.md file — all breaking
      const api = parseApiSurface(extractCodeFromApiMd(baselineContent));
      for (const [name, sym] of api) {
        report.breaking.push({
          type: "removed-export",
          symbol: name,
          kind: sym.kind,
          detail: `Removed ${sym.kind} "${name}" (API file deleted: ${fileName})`,
        });
      }
      continue;
    }

    if (!baselineContent && !currentContent) continue;

    // Both exist — compare
    const oldApi = parseApiSurface(extractCodeFromApiMd(baselineContent));
    const newApi = parseApiSurface(extractCodeFromApiMd(currentContent));
    const changes = compareApiSurfaces(oldApi, newApi);

    report.breaking.push(...changes.breaking);
    report.additive.push(...changes.additive);
    report.potentiallyBreaking.push(...changes.potentiallyBreaking);
  }

  return report;
}

// === Main ===

function main() {
  console.log("===== Step 6: Breaking Change Detection =====");
  console.log(`Baseline: ${baselineSha}`);
  console.log(`Fail on breaking: ${failOnBreaking}`);
  console.log("");

  // Determine packages to check
  let packages = [];
  if (packagesFile && fs.existsSync(packagesFile)) {
    // Read from file (one package dir per line)
    packages = fs
      .readFileSync(packagesFile, "utf8")
      .trim()
      .split("\n")
      .filter(Boolean)
      .map((line) => line.split("\t")[0].trim());
  } else {
    // Auto-detect: find all arm-* packages with review/ directories
    const findCmd =
      process.platform === "win32"
        ? `powershell -Command "Get-ChildItem -Recurse -Directory -Filter 'arm-*' sdk | Where-Object { Test-Path (Join-Path $_.FullName 'review') } | ForEach-Object { $_.FullName }"`
        : 'find sdk -type d -name "arm-*" -exec test -d "{}/review" ";" -print';
    try {
      const output = execSync(findCmd, { encoding: "utf8", cwd: sdkRoot });
      packages = output.trim().split("\n").filter(Boolean);
    } catch {
      console.log("No packages with review/ directories found.");
      return;
    }
  }

  if (packages.length === 0) {
    console.log("No packages to check.");
    return;
  }

  console.log(`Checking ${packages.length} packages for breaking changes...`);
  console.log("");

  const results = [];
  let totalBreaking = 0;
  let totalPotentiallyBreaking = 0;
  let totalAdditive = 0;
  let packagesWithBreaking = 0;
  let packagesWithChanges = 0;
  let packagesUnchanged = 0;

  for (const pkg of packages) {
    const pkgDir = path.isAbsolute(pkg) ? pkg : path.join(sdkRoot, pkg);
    if (!fs.existsSync(pkgDir)) continue;

    const report = processPackage(pkgDir);
    const hasBreaking = report.breaking.length > 0 || report.potentiallyBreaking.length > 0;
    const hasChanges = hasBreaking || report.additive.length > 0;

    if (hasBreaking) {
      packagesWithBreaking++;
      const pkgName = path.relative(sdkRoot, pkgDir).replace(/\\/g, "/");
      console.log(`  ⚠️  ${pkgName}`);
      for (const change of report.breaking) {
        console.log(`      ❌ [BREAKING] ${change.detail}`);
      }
      for (const change of report.potentiallyBreaking) {
        console.log(`      ⚡ [POTENTIALLY BREAKING] ${change.detail}`);
        if (verbose) {
          console.log(`         old: ${change.old}`);
          console.log(`         new: ${change.new}`);
        }
      }
    } else if (hasChanges) {
      packagesWithChanges++;
      if (verbose) {
        const pkgName = path.relative(sdkRoot, pkgDir).replace(/\\/g, "/");
        console.log(`  ✅ ${pkgName} (additive only: ${report.additive.length} changes)`);
      }
    } else {
      packagesUnchanged++;
    }

    totalBreaking += report.breaking.length;
    totalPotentiallyBreaking += report.potentiallyBreaking.length;
    totalAdditive += report.additive.length;

    results.push({
      pkg: path.relative(sdkRoot, pkgDir).replace(/\\/g, "/"),
      ...report,
    });
  }

  // Summary
  console.log("");
  console.log("========== BREAKING CHANGE SUMMARY ==========");
  console.log(`Packages checked    : ${packages.length}`);
  console.log(`With breaking changes: ${packagesWithBreaking}`);
  console.log(`With additive only  : ${packagesWithChanges}`);
  console.log(`Unchanged           : ${packagesUnchanged}`);
  console.log("");
  console.log(`Total breaking      : ${totalBreaking}`);
  console.log(`Total potentially breaking: ${totalPotentiallyBreaking}`);
  console.log(`Total additive      : ${totalAdditive}`);
  console.log("==============================================");

  // List all packages with breaking changes
  if (packagesWithBreaking > 0) {
    console.log("");
    console.log("Packages with breaking changes:");
    for (const r of results) {
      if (r.breaking.length > 0 || r.potentiallyBreaking.length > 0) {
        console.log(`  - ${r.pkg} (${r.breaking.length} breaking, ${r.potentiallyBreaking.length} potentially breaking)`);
      }
    }
  }

  // Exit with error if breaking changes found
  if (failOnBreaking && (totalBreaking > 0 || totalPotentiallyBreaking > 0)) {
    console.log("");
    console.log("❌ Breaking changes detected. Use --no-fail to suppress exit code.");
    process.exit(1);
  }
}

main();
